starterCode.javascript:
function reverseString(s) {
  let result = '';
  for (let i = 0; i < s.length; i++) {
    result = s[i];
  }
  return result;
}

buggyStarterCode.javascript:
function reverseString(s) {
  let result = '';
  for (let i = s.length; i >= 0; i--) {
    result = s[i];
  }
  return result;
}

solutions.javascript:
// Solution
function reverseString(s) {
  let result = '';
  for (let i = s.length - 1; i >= 0; i--) {
    result += s[i];
  }
  return result;
}
